import React from "react";

function Login() {
  return (
    <div style={{ padding: "30px" }}>
      <h1>Login Page</h1>

      <input
        type="email"
        placeholder="Enter Email"
        style={{
          display: "block",
          margin: "10px 0",
          padding: "10px",
        }}
      />

      <input
        type="password"
        placeholder="Enter Password"
        style={{
          display: "block",
          margin: "10px 0",
          padding: "10px",
        }}
      />

      <button>Login</button>
    </div>
  );
}

export default Login;
